import 'dart:convert'; import 'package:http/http.dart' as http; void main() async { var rEng = await http.get(Uri.parse('https://www.mp3quran.net/api/v3/reciters?language=eng')); var rAr = await http.get(Uri.parse('https://www.mp3quran.net/api/v3/reciters?language=ar')); var e = jsonDecode(rEng.body)['reciters']; var a = jsonDecode(utf8.decode(rAr.bodyBytes))['reciters']; print(e[0]); print(a.firstWhere((x)=>x['id']==e[0]['id'])); }
